I cannot generate a 3D model file (such as `.obj`, `.fbx`, or `.gltf`) directly, as I am a text-based AI. However, I can provide you with the **complete code to render a 3D house** using **Three.js**, a popular JavaScript library for 3D graphics in the browser.

You can copy the code below, save it as an `.html` file (e.g., `house.html`), and open it in any modern web browser to see the result.

### 3D House Renderer (Three.js)

This code creates a procedural house with a roof, walls, a door, and a window, complete with lighting and shadows.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>3D House Model</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">3D House Model (Click & Drag to Rotate)</div>

    <!-- Import Three.js from CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 20);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // 2. Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;

        // 3. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 4. Materials
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0xE0E0E0 }); // White walls
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513 }); // Brown roof
        const doorMaterial = new THREE.MeshStandardMaterial({ color: 0x4a3c31 }); // Dark wood
        const windowMaterial = new THREE.MeshStandardMaterial({ color: 0x87CEEB, transparent: true, opacity: 0.6 });
        const grassMaterial = new THREE.MeshStandardMaterial({ color: 0x4caf50 });

        // 5. Building the House
        const houseGroup = new THREE.Group();

        // Floor
        const floorGeo = new THREE.BoxGeometry(10, 1, 10);
        const floor = new THREE.Mesh(floorGeo, grassMaterial);
        floor.position.y = -0.5;
        floor.receiveShadow = true;
        houseGroup.add(floor);

        // Walls
        const wallHeight = 4;
        const wallGeo = new THREE.BoxGeometry(10, wallHeight, 1);
        const wall1 = new THREE.Mesh(wallGeo, wallMaterial);
        wall1.position.set(0, wallHeight / 2, 5);
        wall1.castShadow = true;
        wall1.receiveShadow = true;
        houseGroup.add(wall1);

        const wall2 = new THREE.Mesh(wallGeo, wallMaterial);
        wall2.position.set(0, wallHeight / 2, -5);
        wall2.castShadow = true;
        wall2.receiveShadow = true;
        houseGroup.add(wall2);

        const wall3 = new THREE.Mesh(wallGeo, wallMaterial);
        wall3.rotation.y = Math.PI / 2;
        wall3.position.set(5, wallHeight / 2, 0);
        wall3.castShadow = true;
        wall3.receiveShadow = true;
        houseGroup.add(wall3);

        const wall4 = new THREE.Mesh(wallGeo, wallMaterial);
        wall4.rotation.y = Math.PI / 2;
        wall4.position.set(-5, wallHeight / 2, 0);
        wall4.castShadow = true;
        wall4.receiveShadow = true;
        houseGroup.add(wall4);

        // Door
        const doorGeo = new THREE.BoxGeometry(2, 3, 0.2);
        const door = new THREE.Mesh(doorGeo, doorMaterial);
        door.position.set(0, 1.5, 4.9);
        door.castShadow = true;
        houseGroup.add(door);

        // Window
        const winGeo = new THREE.BoxGeometry(2, 1.5, 0.1);
        const windowMesh = new THREE.Mesh(winGeo, windowMaterial);
        windowMesh.position.set(0, 3, 4.9);
        windowMesh.castShadow = true;
        houseGroup.add(windowMesh);

        // Roof
        const roofGeo = new THREE.ConeGeometry(9, 4, 4);
        const roof = new THREE.Mesh(roofGeo, roofMaterial);
        roof.position.y = wallHeight + 2;
        roof.rotation.y = Math.PI / 4;
        roof.castShadow = true;
        roof.receiveShadow = true;
        houseGroup.add(roof);

        scene.add(houseGroup);

        // 6. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle window resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### How to use this:
1.  **Copy** the code block above.
2.  **Paste** it into a text editor (like Notepad, TextEdit, or VS Code).
3.  **Save** the file as `house.html`.
4.  **Double-click** the file to open it in Chrome, Firefox, or Edge.

### Features included:
*   **Procedural Geometry:** The house is built using basic shapes (Boxes, Cones) grouped together.
*   **Lighting:** Includes ambient light and a directional light that casts realistic shadows.
*   **Interactivity:** You can click and drag to rotate the camera, or scroll to zoom in/out.
*   **Responsive:** The canvas resizes automatically if you change the browser window size.
